const projects = $('Fetch Projects').all().map(i => i.json).filter(p => p && p.id);
const investments = $('Fetch Investments').all().map(i => i.json).filter(r => r && r.id);
const tasks = $('Fetch Team Tasks').all().map(i => i.json).filter(t => t && t.id);
const now = Date.now();
const isDone = t => String(t.status) === 'Done';
const isOverdue = t => { if (isDone(t)) { return false; } const d = new Date(t.due_date).getTime(); return !isNaN(d) && d < now; };
const byStatus = {};
projects.forEach(p => { const s = String(p.status || 'Unknown'); byStatus[s] = (byStatus[s] || 0) + 1; });
const totalInvestment = investments.reduce((a, r) => a + (Number(r.total_investment) || 0), 0);
const roiVals = investments.filter(r => r.estimated_roi_percent !== null && r.estimated_roi_percent !== undefined).map(r => Number(r.estimated_roi_percent)).filter(v => !isNaN(v));
const avgRoi = roiVals.length ? Math.round((roiVals.reduce((a, b) => a + b, 0) / roiVals.length) * 100) / 100 : null;
const doneCount = tasks.filter(isDone).length;
const overdueCount = tasks.filter(isOverdue).length;
const projSummaries = projects.map(p => { const inv = investments.filter(r => r.project_id === p.id); const ptasks = tasks.filter(t => t.project_id === p.id); return { name: p.name, status: p.status, property_type: p.property_type, property_location: p.property_location, total_investment: inv.reduce((a, r) => a + (Number(r.total_investment) || 0), 0), estimated_roi_percent: inv.length && inv[0].estimated_roi_percent !== null && inv[0].estimated_roi_percent !== undefined ? Number(inv[0].estimated_roi_percent) : null, task_count: ptasks.length, tasks_done: ptasks.filter(isDone).length, tasks_overdue: ptasks.filter(isOverdue).length }; });
const aggregates = { as_of: new Date().toISOString(), currency: 'INR', project_count: projects.length, projects_by_status: byStatus, total_investment_inr: totalInvestment, average_estimated_roi_percent: avgRoi, task_totals: { total: tasks.length, completed: doneCount, overdue: overdueCount, completion_rate: tasks.length ? Math.round((doneCount / tasks.length) * 100) / 100 : 0 }, projects: projSummaries };
return [{ json: { aggregates: aggregates, project_ids: projects.map(p => p.id) } }];

const projectIds = $('Aggregate Portfolio Data').first().json.project_ids || [];
const items = $input.all();
function collectStrings(v, out) { if (typeof v === 'string') { out.push(v); return; } if (Array.isArray(v)) { v.forEach(x => collectStrings(x, out)); return; } if (v && typeof v === 'object') { ['text', 'merged', 'output', 'completion', 'response', 'content', 'message'].forEach(k => { if (v[k] !== undefined) collectStrings(v[k], out); }); } }
function tryParseArray(s) { if (typeof s !== 'string') return null; let t = s.trim(); t = t.replace(/```json/gi, '').replace(/```/g, '').trim(); const first = t.indexOf('['); const last = t.lastIndexOf(']'); if (first === -1 || last === -1 || last <= first) return null; t = t.slice(first, last + 1); try { const p = JSON.parse(t); return Array.isArray(p) ? p : null; } catch (e) { return null; } }
let arr = null;
let rawAll = '';
for (const it of items) { const out = []; collectStrings(it.json, out); rawAll = rawAll + out.join('\n'); for (const s of out) { arr = tryParseArray(s); if (arr) break; } if (arr) break; }
if (!arr) { arr = tryParseArray(rawAll); }
const allowedTypes = ['Timeline', 'Budget', 'ROI', 'Risk'];
const valid = (arr || []).filter(p => p && typeof p === 'object' && allowedTypes.indexOf(String(p.projection_type)) !== -1 && p.projection_title && p.data && typeof p.data === 'object');
if (!valid.length) { return [{ json: { parse_ok: false, error_message: 'Could not parse a valid projections JSON array from the AI response', raw_snippet: rawAll.slice(0, 500) } }]; }
return valid.map(p => { const data = p.data; let cl = Number(data.confidence_level); if (isNaN(cl)) { cl = 0.5; } if (cl > 1) { cl = cl / 100; } if (cl < 0) { cl = 0; } if (cl > 1) { cl = 1; } data.confidence_level = Math.round(cl * 100) / 100; if (!Array.isArray(data.insights)) { data.insights = data.insights ? [String(data.insights)] : []; } return { json: { parse_ok: true, projection_type: String(p.projection_type), projection_title: String(p.projection_title), data: data, generated_from_projects: projectIds, recipients_emails: ['akashsakhrani05@gmail.com'] } }; });
